"use client";

import { useEffect, useState } from "react";
import dynamic from "next/dynamic";

// Dynamically import the MagicBell component to prevent SSR issues
const MagicBellInboxClient = dynamic(
  () => import("./MagicBellInboxClient"),
  { ssr: false }
);

interface Config {
  token: string;
  email: string;
  apiKey: string;
}

export default function MagicBellInbox() {
  const [config, setConfig] = useState<Config | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    fetch("/api/config")
      .then((res) => res.json())
      .then((data) => {
        if (data.error) {
          setError(data.error);
        } else {
          setConfig(data);
        }
      })
      .catch((err) => setError(err.message));
  }, []);

  if (error) {
    return <div style={{ color: "red", fontSize: "0.75rem" }}>Error: {error}</div>;
  }

  if (!config) {
    return <div style={{ width: 40, height: 40 }} />;
  }

  return <MagicBellInboxClient token={config.token} email={config.email} />;
}

"use client";

import "@magicbell/react/styles/floating-inbox.css";
import "@magicbell/react/styles/inbox.css";
import "@magicbell/react/styles/inline-notification.css";

import { useContext, useEffect, useRef, useState } from "react";
import Provider from "@magicbell/react/context-provider";
import FloatingInbox from "@magicbell/react/floating-inbox";
import MagicBellContext from "@magicbell/react/dist/commonjs/internal/context/magicbell.context.js";

// ─── Types ────────────────────────────────────────────────────────────────────

interface Notification {
  id: string;
  title?: string;
  content?: string;
  readAt?: string | null;
  sentAt?: string | null;
  archivedAt?: string | null;
  discardedAt?: string | null;
  actionUrl?: string | null;
  [key: string]: unknown;
}

interface Tab {
  label: string;
  /** storeId - used to uniquely identify the tab's filter. The "all" storeId links to global unread count */
  storeId: "all" | "unread";
  filter: (n: Notification) => boolean;
}

const TABS: Tab[] = [
  {
    label: "All",
    storeId: "all",
    filter: (n) => !n.discardedAt && !n.archivedAt,
  },
  {
    label: "Unread",
    storeId: "unread",
    filter: (n) => !n.discardedAt && !n.archivedAt && !n.readAt,
  },
];

// ─── Tabbed Inbox ─────────────────────────────────────────────────────────────

interface TabbedInboxProps {
  height?: number;
  width?: number;
  floating?: boolean;
  onNotificationClick?: (event: Event, detail: { notification: Notification }) => void;
}

function TabbedInbox({ height = 400, floating, onNotificationClick }: TabbedInboxProps) {
  const ctx = useContext(MagicBellContext as React.Context<any>);
  const [activeTab, setActiveTab] = useState<"all" | "unread">("all");
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [ready, setReady] = useState(false);
  const observerRef = useRef<any>(null);
  const headerRef = useRef<HTMLDivElement>(null);
  const [headerHeight, setHeaderHeight] = useState(0);

  useEffect(() => {
    if (headerRef.current) {
      setHeaderHeight(headerRef.current.offsetHeight || 0);
    }
  }, []);

  useEffect(() => {
    // Stop any previous observer
    if (observerRef.current) {
      observerRef.current.stop?.();
    }

    const activeTabDef = TABS.find((t) => t.storeId === activeTab)!;

    // Query the notification store directly based on active tab
    const baseQuery =
      activeTab === "unread"
        ? { discardedAt: null, archivedAt: null, readAt: null }
        : { discardedAt: null, archivedAt: null };

    const observer = ctx.notifications
      .find(baseQuery, { sort: { sentAt: -1 } })
      .watch((docs: Notification[]) => {
        setReady(true);
        setNotifications(docs);
      });

    observerRef.current = observer;

    return () => {
      observer?.stop?.();
    };
  }, [ctx.notifications, activeTab]);

  const bodyHeight = height - headerHeight - 48; // 48px for footer approx

  return (
    <div
      className="magicbell--inbox"
      data-floating={floating ? "true" : null}
      style={{ height: "100%", width: "100%" }}
    >
      {/* Header with tabs */}
      <div
        className="magicbell--inbox-header"
        ref={headerRef}
        style={{ flexDirection: "column", alignItems: "stretch", padding: 0, gap: 0 }}
      >
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            padding: "0.75rem 1rem",
          }}
        >
          <div className="magicbell--inbox-header--title">Notifications</div>
          <div className="magicbell--inbox-header--actions">
            <button
              title="Mark all as read"
              className="magicbell--inbox-header--button"
              onClick={() => ctx.notifications.markAllRead()}
            >
              {/* List checkmark icon */}
              <svg
                xmlns="http://www.w3.org/2000/svg"
                width="20"
                height="20"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
              >
                <polyline points="9 11 12 14 22 4" />
                <path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11" />
              </svg>
            </button>
          </div>
        </div>

        {/* Tab bar */}
        <div
          style={{
            display: "flex",
            borderTop: "1px solid var(--magicbell-border-muted)",
          }}
        >
          {TABS.map((tab) => {
            const isActive = activeTab === tab.storeId;
            return (
              <button
                key={tab.storeId}
                onClick={() => setActiveTab(tab.storeId)}
                style={{
                  flex: 1,
                  border: "none",
                  borderBottom: isActive
                    ? "2px solid var(--magicbell-primary-bg)"
                    : "2px solid transparent",
                  background: "none",
                  padding: "0.5rem 0",
                  fontFamily: "var(--magicbell-font-family)",
                  fontSize: "0.875rem",
                  fontWeight: isActive ? 600 : 400,
                  color: isActive
                    ? "var(--magicbell-primary-bg)"
                    : "var(--magicbell-text-muted)",
                  cursor: "pointer",
                  transition: "all 0.15s",
                }}
              >
                {tab.label}
              </button>
            );
          })}
        </div>
      </div>

      {/* Notification list */}
      <div
        style={{
          height: `${bodyHeight}px`,
          overflowY: "auto",
        }}
      >
        {ready && notifications.length === 0 ? (
          <div
            className="magicbell--inbox--empty-state"
            style={{ height: "100%", display: "flex", alignItems: "center", justifyContent: "center" }}
          >
            <p>No {activeTab === "unread" ? "unread " : ""}notifications yet.</p>
          </div>
        ) : (
          <ul style={{ margin: 0, padding: 0, listStyle: "none" }}>
            {notifications.map((notification) => (
              <NotificationItem
                key={notification.id}
                notification={notification}
                onNotificationClick={onNotificationClick}
                onMarkRead={() => ctx.notifications.markAsRead(notification.id)}
              />
            ))}
          </ul>
        )}
      </div>

      {/* Footer */}
      <div className="magicbell--inbox-footer">
        <div className="magicbell--inbox-footer--logo">
          <svg
            width="16"
            height="16"
            viewBox="0 0 32 32"
            fill="currentColor"
            xmlns="http://www.w3.org/2000/svg"
            style={{ marginRight: "0.25rem" }}
          >
            <path d="M16 2C8.268 2 2 8.268 2 16s6.268 14 14 14 14-6.268 14-14S23.732 2 16 2zm0 25c-6.075 0-11-4.925-11-11S9.925 5 16 5s11 4.925 11 11-4.925 11-11 11zm-1-17h2v6h-2zm0 8h2v2h-2z" />
          </svg>
          <span style={{ fontSize: "0.7rem", color: "var(--magicbell-text-muted)" }}>
            Powered by MagicBell
          </span>
        </div>
      </div>
    </div>
  );
}

// ─── Notification Item ────────────────────────────────────────────────────────

function NotificationItem({
  notification,
  onNotificationClick,
  onMarkRead,
}: {
  notification: Notification;
  onNotificationClick?: (event: Event, detail: { notification: Notification }) => void;
  onMarkRead: () => void;
}) {
  const isUnread = !notification.readAt;
  const date = notification.sentAt
    ? new Date(notification.sentAt).toLocaleDateString(undefined, {
        month: "short",
        day: "numeric",
        hour: "2-digit",
        minute: "2-digit",
      })
    : "";

  const handleClick = (e: React.MouseEvent) => {
    if (isUnread) onMarkRead();
    if (onNotificationClick) {
      onNotificationClick(e.nativeEvent, { notification });
    }
    if (notification.actionUrl) {
      window.open(notification.actionUrl as string, "_blank");
    }
  };

  return (
    <li
      className="magicbell--inbox-item"
      data-status={isUnread ? "unread" : "read"}
      onClick={handleClick}
      style={{ cursor: "pointer" }}
    >
      <div className="magicbell--inbox-item--title" style={{ fontWeight: isUnread ? 600 : 400 }}>
        {notification.title || "Notification"}
      </div>
      <div className="magicbell--inbox-item--date">{date}</div>
      {notification.content ? (
        <div className="magicbell--inbox-item--content">{String(notification.content)}</div>
      ) : null}
    </li>
  );
}

// ─── Provider Wrapper ─────────────────────────────────────────────────────────

interface Props {
  token: string;
  email: string;
}

export default function MagicBellInboxClient({ token, email }: Props) {
  return (
    <Provider token={token}>
      <FloatingInbox
        placement="bottom-end"
        height={500}
        width={420}
        InboxComponent={TabbedInbox}
      />
    </Provider>
  );
}

