"use client";

import "@magicbell/react/styles/floating-inbox.css";
import "@magicbell/react/styles/inbox.css";
import "@magicbell/react/styles/inline-notification.css";

import { useContext, useEffect, useRef, useState } from "react";
import Provider from "@magicbell/react/context-provider";
import FloatingInbox from "@magicbell/react/floating-inbox";
// Access the internal MagicBell context to query the notification store
// eslint-disable-next-line @typescript-eslint/no-require-imports
const MagicBellContext = require("@magicbell/react/dist/commonjs/internal/context/magicbell.context.js").default;

// ─── Types ────────────────────────────────────────────────────────────────────

interface Notification {
  id: string;
  title?: string;
  content?: string;
  readAt?: string | null;
  sentAt?: string | null;
  archivedAt?: string | null;
  discardedAt?: string | null;
  actionUrl?: string | null;
  [key: string]: unknown;
}

type TabId = "all" | "unread";

interface TabDef {
  label: string;
  /**
   * storeId must be "all" to link to global unread count on the bell button.
   * The InlineNotification (badge dot) in InboxButton queries all notifications
   * with readAt=null regardless of tabs – this is purely visual tab filtering.
   */
  storeId: TabId;
  query: Record<string, null>;
}

const TABS: TabDef[] = [
  {
    label: "All",
    storeId: "all",
    query: { discardedAt: null, archivedAt: null },
  },
  {
    label: "Unread",
    storeId: "unread",
    query: { discardedAt: null, archivedAt: null, readAt: null },
  },
];

// ─── Notification Item ────────────────────────────────────────────────────────

function NotificationItem({
  notification,
  onMarkRead,
  onNotificationClick,
}: {
  notification: Notification;
  onMarkRead: () => void;
  onNotificationClick?: (event: Event, detail: { notification: Notification }) => void;
}) {
  const isUnread = !notification.readAt;
  const date = notification.sentAt
    ? new Date(notification.sentAt).toLocaleDateString(undefined, {
        month: "short",
        day: "numeric",
        hour: "2-digit",
        minute: "2-digit",
      })
    : "";

  const handleClick = (e: React.MouseEvent) => {
    if (isUnread) onMarkRead();
    if (onNotificationClick) {
      onNotificationClick(e.nativeEvent, { notification });
    }
    if (notification.actionUrl) {
      window.open(notification.actionUrl as string, "_blank");
    }
  };

  return (
    <li
      className="magicbell--inbox-item"
      data-status={isUnread ? "unread" : "read"}
      onClick={handleClick}
    >
      <div
        className="magicbell--inbox-item--title"
        style={{ fontWeight: isUnread ? 600 : 400 }}
      >
        {notification.title || "Notification"}
      </div>
      <div className="magicbell--inbox-item--date">{date}</div>
      {notification.content ? (
        <div className="magicbell--inbox-item--content">
          {String(notification.content)}
        </div>
      ) : null}
    </li>
  );
}

// ─── Tabbed Inbox ─────────────────────────────────────────────────────────────

interface TabbedInboxProps {
  height?: number;
  width?: number;
  floating?: boolean;
  onNotificationClick?: (
    event: Event,
    detail: { notification: Notification }
  ) => void;
}

/**
 * TabbedInbox – a custom Inbox component with "All" and "Unread" tabs.
 *
 * Badge count: The bell button's badge (InlineNotification with variant="dot")
 * queries the global notification store for any notification with readAt=null.
 * This is completely independent of which tab is shown inside the inbox.
 * The badge will always reflect the global unread count.
 */
function TabbedInbox({
  height = 500,
  floating,
  onNotificationClick,
}: TabbedInboxProps) {
  const ctx = useContext(MagicBellContext);
  const [activeTab, setActiveTab] = useState<TabId>("all");
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [ready, setReady] = useState(false);
  const observerRef = useRef<{ stop?: () => void } | null>(null);
  const headerRef = useRef<HTMLDivElement>(null);
  const [headerHeight, setHeaderHeight] = useState(0);

  // Measure header height after mount
  useEffect(() => {
    requestAnimationFrame(() => {
      if (headerRef.current) {
        setHeaderHeight(headerRef.current.offsetHeight);
      }
    });
  }, []);

  // Subscribe to notifications based on active tab
  useEffect(() => {
    observerRef.current?.stop?.();

    const tab = TABS.find((t) => t.storeId === activeTab)!;
    const observer = ctx.notifications
      .find(tab.query, { sort: { sentAt: -1 } })
      .watch((docs: Notification[]) => {
        setReady(true);
        setNotifications(docs);
      });

    observerRef.current = observer;

    return () => {
      observer?.stop?.();
    };
  }, [ctx.notifications, activeTab]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      observerRef.current?.stop?.();
    };
  }, []);

  const FOOTER_HEIGHT = 40;
  const bodyHeight = Math.max(60, height - headerHeight - FOOTER_HEIGHT);

  return (
    <div
      className="magicbell--inbox"
      data-floating={floating ? "true" : null}
      style={{ height: "100%", width: "100%", display: "flex", flexDirection: "column" }}
    >
      {/* ── Header ────────────────────────────────────────────────── */}
      <div
        ref={headerRef}
        className="magicbell--inbox-header"
        style={{
          flexDirection: "column",
          alignItems: "stretch",
          padding: 0,
          gap: 0,
          borderBottom: "none",
        }}
      >
        {/* Title row */}
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            padding: "0.75rem 1rem",
            borderBottom: "1px solid var(--magicbell-border-muted)",
          }}
        >
          <div className="magicbell--inbox-header--title">Notifications</div>
          <div className="magicbell--inbox-header--actions">
            <button
              title="Mark all as read"
              className="magicbell--inbox-header--button"
              onClick={() => ctx.notifications.markAllRead?.()}
            >
              {/* Checkmark icon */}
              <svg
                xmlns="http://www.w3.org/2000/svg"
                width="20"
                height="20"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
              >
                <polyline points="9 11 12 14 22 4" />
                <path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11" />
              </svg>
            </button>
          </div>
        </div>

        {/* Tab bar */}
        <div
          style={{
            display: "flex",
            borderBottom: "1px solid var(--magicbell-border-muted)",
          }}
        >
          {TABS.map((tab) => {
            const isActive = activeTab === tab.storeId;
            return (
              <button
                key={tab.storeId}
                onClick={() => setActiveTab(tab.storeId)}
                style={{
                  flex: 1,
                  border: "none",
                  borderBottom: isActive
                    ? "2px solid var(--magicbell-primary-bg)"
                    : "2px solid transparent",
                  background: "none",
                  padding: "0.625rem 0",
                  fontFamily: "var(--magicbell-font-family)",
                  fontSize: "0.875rem",
                  fontWeight: isActive ? 600 : 400,
                  color: isActive
                    ? "var(--magicbell-primary-bg)"
                    : "var(--magicbell-text-muted)",
                  cursor: "pointer",
                  transition: "color 0.15s, border-color 0.15s",
                }}
              >
                {tab.label}
              </button>
            );
          })}
        </div>
      </div>

      {/* ── Notification list ─────────────────────────────────────── */}
      <div style={{ flex: 1, overflowY: "auto", minHeight: 0 }}>
        {ready && notifications.length === 0 ? (
          <div
            className="magicbell--inbox--empty-state"
            style={{
              height: "100%",
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              justifyContent: "center",
            }}
          >
            <p>No {activeTab === "unread" ? "unread " : ""}notifications yet.</p>
          </div>
        ) : (
          <ul style={{ margin: 0, padding: 0, listStyle: "none" }}>
            {notifications.map((n) => (
              <NotificationItem
                key={n.id}
                notification={n}
                onNotificationClick={onNotificationClick}
                onMarkRead={() => ctx.notifications.markAsRead(n.id)}
              />
            ))}
          </ul>
        )}
      </div>

      {/* ── Footer ────────────────────────────────────────────────── */}
      <div className="magicbell--inbox-footer">
        <div className="magicbell--inbox-footer--logo">
          <span style={{ fontSize: "0.7rem", color: "var(--magicbell-text-muted)" }}>
            Powered by MagicBell
          </span>
        </div>
      </div>
    </div>
  );
}

